# Perl Script: Haversine Distance Calculator

This script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs, handles errors, and provides output in kilometers or miles.

---

## 📌 Script: `haversine_distance.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use JSON;

# Constants
my $KILOMETERS = 1;
my $MILES = 1;

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371; # Earth radius in kilometers

    my $dlat = radians($lat2 - $lat1);
    my $dlon = radians($lon2 - $lat2);

    my $a = sin($dlat/2) ** 2 + cos(radians($lat1)) * cos(radians($lat2)) * sin($dlon/2) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Convert degrees to radians
sub radians {
    return ( $_[0] * pi() / 180 );
}

# Example locations
my %locations = (
    'New York' => { lat => 40.7128, lon => -74.0060 },
    'Tokyo' => { lat => 35.6895, lon => 139.6917 },
);

# Main script
my $help = 0;
my $unit = $KILOMETERS;

GetOptions(
    'h' => \$help,
    'u' => \$unit,
    'm' => \$unit,
) or die "Error in options\n";

if ($help) {
    print "Usage: $0 [options]\n";
    print "Options:\n";
    print "  -h, --help         Show this help message\n";
    print "  -u, --unit=KILOMETERS | -m, --unit=MILES\n";
    print "    Specify the unit (default: KILOMETERS)\n";
    exit;
}

# Check if at least two locations are provided
if (@ARGV < 2) {
    die "Error: At least two locations are required.\n";
}

# Parse locations
my @locations = map { $_->[0] } grep { $_->[1] } @ARGV;

# Validate location data
my %valid_locations = ();
foreach my $loc (@locations) {
    my ($name, $lat, $lon) = split(/\s+/, $loc, 3);
    if (!defined $name || !defined $lat || !defined $lon) {
        die "Error: Invalid location format. Expected: name lat lon\n";
    }
    $valid_locations{$name} = { lat => $lat, lon => $lon };
}

# Check if all locations are valid
my @error_msgs = grep { !exists $valid_locations{$_} } @locations;

if (@error_msgs > 0) {
    die "Error: One or more locations are invalid.\n";
}

# Calculate distance between two locations
my ($loc1, $loc2) = @locations;
my ($loc1_name, $loc2_name) = ( $loc1 =~ /^([^ ]+) \s+ ([^ ]+)$/ ) || (die "Error: Invalid location format\n");
my ($loc1_lat, $loc1_lon) = ( $loc1 =~ /^([^ ]+) \s+ ([^ ]+)$/ ) || (die "Error: Invalid location format\n");
my ($loc2_lat, $loc2_lon) = ( $loc2 =~ /^([^ ]+) \s+ ([^ ]+)$/ ) || (die "Error: Invalid location format\n");

my $distance = haversine_distance($loc1_lat, $loc1_lon, $loc2_lat, $loc2_lon);

# Output
print "Distance between $loc1_name and $loc2_name: \n";
if ($unit == $KILOMETERS) {
    print "$distance kilometers\n";
} elsif ($unit == $MILES) {
    print "$distance miles\n";
}

# Example usage
print "\nExample usage:\n";
print "perl haversine_distance.pl New York Tokyo\n";
print "perl haversine_distance.pl New York Tokyo -u miles\n";
print "perl haversine_distance.pl New York Tokyo -h\n";
