```swift
import Foundation

// Define a Node struct to represent each node in the BST
struct Node {
    var value: Int
    var left: Node?
    var right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define a class for the BST
class BinarySearchTree {
    var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    // Helper function to insert a node into the BST
    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else if value > node!.value {
            node!.right = insertNode(node!.right, value)
        }

        return node
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    // Helper function to delete a node from the BST
    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, perform deletion
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findInOrderSuccessor(node!.right!)
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node
    }

    // Find the in-order successor of a node
    private func findInOrderSuccessor(_ node: Node?) -> Node? {
        var current = node
        while current != nil && current!.left != nil {
            current = current!.left
        }
        return current
    }

    // Traverse the BST in pre-order
    func preOrderTraverse() {
        preOrderTraverse(root)
    }

    // Helper function for pre-order traversal
    private func preOrderTraverse(_ node: Node?) {
        if node != nil {
            print(node!.value, " ", sep: " ")
            preOrderTraverse(node!.left)
            preOrderTraverse(node!.right)
        }
    }

    // Traverse the BST in in-order
    func inOrderTraverse() {
        inOrderTraverse(root)
    }

    // Helper function for in-order traversal
    private func inOrderTraverse(_ node: Node?) {
        if node != nil {
            inOrderTraverse(node!.left)
            print(node!.value, " ", sep: " ")
            inOrderTraverse(node!.right)
        }
    }

    // Traverse the BST in post-order
    func postOrderTraverse() {
        postOrderTraverse(root)
    }

    // Helper function for post-order traversal
    private func postOrderTraverse(_ node: Node?) {
        if node != nil {
            postOrderTraverse(node!.left)
            postOrderTraverse(node!.right)
            print(node!.value, " ", sep: " ")
        }
    }
}
```

### Explanation:

- **Node Struct**: Represents each node in the BST with a value, left child, and right child.
- **BinarySearchTree Class**: Manages the BST with methods for insertion, deletion, and traversal.
  - **insert**: Adds a new node to the BST in the correct position.
  - **delete**: Removes a node while maintaining BST properties.
  - **findInOrderSuccessor**: Helper to find the in-order successor when a node has two children.
- **Traversals**:
  - **preOrderTraverse**: Prints nodes in pre-order (visit root, left, right).
  - **inOrderTraverse**: Prints nodes in in-order (visit left, root, right).
  - **postOrderTraverse**: Prints nodes in post-order (visit left, right, root).

### Efficiency:
- Insertion and deletion are O(log n) in average case, O(n) in worst case (for skewed trees).
- Traversal is O(n) for all operations.

This implementation is clean, efficient, and adheres to the principles of a BST.

