my @numbers;
while (1) {
    my $input = <>;
    chomp $input;
    last if $input eq 'exit';

    if ($input =~ /^-?\d+$/ && $input ne 'exit') {
        push @numbers, $input;
    } else {
        die "Invalid input: $input. Please enter integers only.\n";
    }
}

# Sort the array in descending order using merge sort
my $sorted = merge_sort(\@numbers);

# Print the sorted array
print "Sorted array in descending order:\n";
print " " . join(" ", @sorted) . "\n";
